nom.skip.fwd   = function(step) { let val; val = step; if (!step) val = 5; for (s = 0; s < val; s++) { nom.next(); } return 0; }
nom.skip.end   = function()     { nom.now.value = nom.length - 1; nom.set(nom.now.value); return 0; }
nom.pause      = function() { return 0; }
